css:
#background {
	position: absolute;
	z-index: 0;
	min-height: 143%;
	min-width: 93%;
}

#content {
	z-index: 1;
}

#bg-text {
	color: black;
	font-size: 120px;
	transform: rotate(315deg);
	-webkit-transform: rotate(315deg);
	opacity: 24%;
	text-align: center;
}

#small-bg-text {
	font-size: 20px;
}

html:
{% if letter_head and not no_letterhead %}<div class="letter-head">{{ letter_head }}</div>{% endif %}
<div style="border:1px solid #aaa; border-radius: 0px; border-collapse: collapse;" class="container-fluid">
    {% if doc.docstatus == 0 or doc.docstatus == 2 %}
    <div id="background">
        <p id="bg-text">
            {% if doc.docstatus == 0 %}
            Draft
            <br>
            <span class="small-bg-text" style="font-size: 20px;">This Document is pending for approval</span>
            {% else %}
            Cancelled
            <br>
            <span class="small-bg-text" style="font-size: 20px;">This Document is Cancelled</span>
            {% endif %}
        </p>
    </div>
    {% endif %}
    {% if doc.purpose in ['Send to Warehouse', 'Material Receipt', 'Material Issue'] %}
    <div id="content">
        <div class="row" style="border-bottom:1px solid #666;display: flex;">
            {% if doc.purpose in ['Send to Warehouse', 'Material Issue'] %}
                <div class="col-xs-4" style="border-right:1px solid #ddd;">
                    <div class="col-xs-12" style="font-size:95%; padding-left: 0;">
                        <small>From:</small>
                        {% set from_warehouse = frappe.db.get_value("Supplier", doc.from_warehouse, "supplier_name") %}
                        <br><strong>{{from_warehouse}}</strong>
                        {% set from_address = get_supplier_address_display(doc.from_warehouse) %}
                        {% if from_address %}
                        <br>{{from_address}}
                        {% endif %}
                    </div>
                </div>
            {% elif doc.transfer_supplier %}
                <div class="col-xs-4" style="border-right:1px solid #ddd;">
                    <div class="col-xs-12" style="font-size:95%; padding-left: 0;">
                        <small>From:</small>
                        {% set from_warehouse = frappe.db.get_value("Supplier", doc.transfer_supplier, "supplier_name") %}
                        <br><strong>{{from_warehouse}}</strong>
                        {% set from_address = get_supplier_address_display(doc.transfer_supplier) %}
                        {% if from_address %}
                        <br>{{from_address}}
                        {% endif %}
                    </div>
                </div>
            {% endif %}
            {% if doc.purpose in ['Send to Warehouse', 'Material Receipt'] %}
                <div class="col-xs-4" style="border-right:1px solid #ddd;">
                    <div class="col-xs-12" style="font-size:95%; padding-left: 0;">
                        <small>To:</small>
                        {% set to_warehouse = frappe.db.get_value("Supplier", doc.to_warehouse, "supplier_name") %}
                        <br><strong>{{to_warehouse}}</strong>
                        {% set to_address = get_supplier_address_display(doc.to_warehouse) %}
                        {% if to_address %}
                        <br>{{to_address}}
                        {% endif %}
                    </div>
                </div>
            {% elif doc.transfer_supplier %}
                <div class="col-xs-4" style="border-right:1px solid #ddd;">
                    <div class="col-xs-12" style="font-size:95%; padding-left: 0;">
                        <small>To:</small>
                        {% set to_warehouse = frappe.db.get_value("Supplier", doc.transfer_supplier, "supplier_name") %}
                        <br><strong>{{to_warehouse}}</strong>
                        {% set to_address = get_supplier_address_display(doc.transfer_supplier) %}
                        {% if to_address %}
                        <br>{{to_address}}
                        {% endif %}
                    </div>
                </div>
            {% endif %}
            <div class="col-xs-4" style="border-left:1px solid #ddd;">
                <div class="row" style="border-bottom:1px solid #ddd;">
                    <div class="col-xs-12 text-center" style="padding-left:0px;"><strong>Delivery Challan</strong></div>
                </div>
                <div class="row" style="border-bottom:1px solid #ddd;">
                    <div class="col-xs-5 text-right" style=" padding-right: 4px; padding-left:0px;"><small>Date:</small></div>
                    <div class="col-xs-7" style="padding-left:0px;"><strong>{{doc.get_formatted("posting_date")}}</strong></div>
                </div>
                <div class="row" style="border-bottom:1px solid #ddd;">
                    <div class="col-xs-5 text-right" style=" padding-right: 4px; padding-left:0px;"><small>No.:</small></div>
                    <div class="col-xs-7" style="padding-left:0px;"><strong>{{doc.name}}</strong></div>
                </div>
                <div class="row" style="border-bottom:1px solid #ddd;">
                    <div class="col-xs-5 text-right" style=" padding-right: 4px; padding-left:0px;"><small>Process:</small></div>
                    <div class="col-xs-7" style="padding-left:0px;"><strong>Transfer</strong></div>
                </div>
                {% if doc.vehicle_no %}
                    <div class="row" style="border-bottom:1px solid #ddd;">
                        <div class="col-xs-5 text-right" style=" padding-right: 4px; padding-left:0px;"><small>Vehicle No:</small></div>
                        <div class="col-xs-7" style="padding-left:0px;"><strong>{{ doc.vehicle_no }}</strong></div>
                    </div>
                {% endif %}
            </div>
        </div>
        <div class="row" style="border-bottom:1px solid #666;">
            <div class="col-xs-12 text-center">Particulars</div>
        </div>
        <div class="row">
            {% set entries = json.loads(doc.dispatch_colour_details) if doc.dispatch_colour_details else [] %}
            {% if entries %}
                {% for entry in entries %}
                    {% set cd = entry.get("grid", {}) %}
                    {% set ipd = frappe.db.get_value("Lot", entry.get("lot"), "production_detail") %}
                    {% set pmode = frappe.db.get_value("Item Production Detail", ipd, "packing_mode") if ipd else None %}
                    <div class="col-xs-12" style="padding-left:0; margin-top:6px;"><strong>{{ entry.get("lot", "") }} &mdash; {{ entry.get("item", "") }}</strong></div>
                    {% if cd %}
                        {% if pmode == "Size Wise Packing" %}
                            {% set sizes = [] %}
                            {% for colour, row in cd.items() %}{% for size in row.keys() %}{% if size not in sizes %}{% set _ = sizes.append(size) %}{% endif %}{% endfor %}{% endfor %}
                            {% set col_tot = namespace(d={}) %}
                            {% set grand = namespace(t=0) %}
                            <table class="table table-sm table-bordered">
                                <tr>
                                    <th>Colour</th>
                                    {% for size in sizes %}<th class="text-center">{{ size }}</th>{% endfor %}
                                    <th class="text-center">Boxes</th>
                                </tr>
                                {% for colour, row in cd.items() %}
                                    {% set rs = namespace(t=0) %}
                                    <tr>
                                        <td>{{ colour }}</td>
                                        {% for size in sizes %}{% set v = row.get(size, 0) %}{% set rs.t = rs.t + v %}{% set _ = col_tot.d.update({size: col_tot.d.get(size, 0) + v}) %}<td class="text-center">{{ (v | round(2)) if v else "" }}</td>{% endfor %}
                                        {% set grand.t = grand.t + rs.t %}
                                        <td class="text-center"><strong>{{ rs.t | round(2) }}</strong></td>
                                    </tr>
                                {% endfor %}
                                <tr>
                                    <td><strong>Total</strong></td>
                                    {% for size in sizes %}<td class="text-center"><strong>{{ col_tot.d.get(size, 0) | round(2) }}</strong></td>{% endfor %}
                                    <td class="text-center"><strong>{{ grand.t | round(2) }}</strong></td>
                                </tr>
                            </table>
                        {% else %}
                            {% set grand = namespace(t=0) %}
                            <table class="table table-sm table-bordered" style="width:auto; min-width:260px;">
                                <tr>
                                    <th>Colour</th>
                                    <th class="text-center">Boxes</th>
                                </tr>
                                {% for colour, row in cd.items() %}
                                    {% set rs = namespace(t=0) %}
                                    {% for size, v in row.items() %}{% set rs.t = rs.t + v %}{% endfor %}
                                    {% set grand.t = grand.t + rs.t %}
                                    <tr>
                                        <td>{{ colour }}</td>
                                        <td class="text-center"><strong>{{ rs.t | round(2) }}</strong></td>
                                    </tr>
                                {% endfor %}
                                <tr>
                                    <td><strong>Total</strong></td>
                                    <td class="text-center"><strong>{{ grand.t | round(2) }}</strong></td>
                                </tr>
                            </table>
                        {% endif %}
                    {% endif %}
                {% endfor %}
            {% else %}
                <div class="col-xs-12 text-center">(No colour-wise dispatch details on this Stock Entry.)</div>
            {% endif %}
        </div>
        <div class="row" style="border-bottom:1px solid #666;border-top:1px solid #666;">
            <div class="col-xs-12">Estimated Value: {{ frappe.utils.fmt_money(doc.total_amount, currency="₹") }}</div>
        </div>
        {% if doc.terms_and_condition %}
            {% set terms = frappe.get_all("Terms and Condition Detail", filters={"parent": doc.terms_and_condition, "parenttype": "Terms and Condition"}, fields=["term"], order_by="idx asc") %}
            {% if terms %}
                <div class="row" style="border-bottom:1px solid #666;">
                    <div class="col-xs-12">
                        <strong>Terms and Conditions:</strong>
                        <ol style="margin:4px 0 4px 18px;padding:0;">
                            {% for row in terms %}
                                <li style="margin-bottom:2px;">{{ row.term }}</li>
                            {% endfor %}
                        </ol>
                    </div>
                </div>
            {% endif %}
        {% endif %}
        <div class="row">
            {% set company = frappe.db.get_single_value("Company Settings", "company") %}
            <div class="col-xs-6 text-center" style="border-right:1px solid #666;">
                Receiver's Signature
                <br><br><br>
                <div class="row text-left">
                    <div class="col-xs-6">Name:</div>
                    <div class="col-xs-6">Designation:</div>
                </div>
            </div>
            <div class="col-xs-6 text-right">
                <small>For </small>
                <strong>{{ company }}</strong>
                <br><br><br>
                Authorized Signatory
            </div>
        </div>
    </div>
    {% endif %}
</div>
{% if footer and not no_letterhead %}<div class="letter-head-footer">{{ footer }}</div>{% endif %}
